def _fmt_num(x, nd=2):
    try:
        if x is None or pd.isna(x):
            return "无数据"
        return f"{float(x):.{nd}f}"
    except Exception:
        return str(x)

def _df_count(df):
    return 0 if df is None else int(len(df))

def _find_col(df, keywords, exclude=()):
    if df is None:
        return None
    for c in df.columns:
        lc = str(c).lower()
        if all(k.lower() in lc for k in keywords) and not any(e.lower() in lc for e in exclude):
            return c
    return None

def _candidate_summary(df, label):
    n = _df_count(df)
    if n == 0:
        return f"{label}：筛查范围内未形成明确候选源。"
    name_col = _find_col(df, ["name"])
    dist_col = _find_col(df, ["distance"])
    pm_candidate_cols = [c for c in df.columns if str(c).lower() in ("pm", "pm_emission", "daily_pm", "hourly_pm") or "pm" == str(c).lower().split("_")[-1]]
    lines = [f"{label}：筛查得到 {n} 个候选源。"]
    if dist_col is not None and pd.api.types.is_numeric_dtype(df[dist_col]):
        d = pd.to_numeric(df[dist_col], errors="coerce")
        if d.notna().any():
            lines.append(f"最近距离约 {_fmt_num(d.min()/1000, 2)} km，中位距离约 {_fmt_num(d.median()/1000, 2)} km。")
    if pm_candidate_cols:
        vals = []
        for c in pm_candidate_cols:
            s = pd.to_numeric(df[c], errors="coerce")
            if s.notna().any():
                vals.append(f"{c}合计{_fmt_num(s.sum(), 2)}、最大{_fmt_num(s.max(), 2)}")
        if vals:
            lines.append("颗粒物排放指标汇总：" + "；".join(vals[:3]) + "。")
    if name_col is not None:
        sample_df = df.copy()
        if dist_col is not None and pd.api.types.is_numeric_dtype(sample_df[dist_col]):
            sample_df = sample_df.sort_values(dist_col)
        names = [str(x) for x in sample_df[name_col].dropna().astype(str).head(3).tolist()]
        if names:
            lines.append("距离优先的重点核查对象包括：" + "、".join(names) + ("等。" if n > 3 else "。"))
    return "".join(lines)

def _dust_summary(df):
    n = _df_count(df)
    if n == 0:
        return "扬尘监测：峰值时段周边扬尘站未提供可用于支撑的同步PM10证据。"
    pm_col_local = _find_col(df, ["pm10"])
    lines = [f"扬尘监测：峰值关联时段共有 {n} 条有效扬尘站记录。"]
    if pm_col_local is not None:
        s = pd.to_numeric(df[pm_col_local], errors="coerce")
        if s.notna().any():
            lines.append(f"PM10均值约 {_fmt_num(s.mean(), 2)}，最大值约 {_fmt_num(s.max(), 2)}。")
    status_col = _find_col(df, ["status"])
    if status_col is not None:
        vc = df[status_col].dropna().astype(str).value_counts().to_dict()
        if vc:
            lines.append("施工状态记录：" + "、".join([f"{k}{v}条" for k, v in vc.items()]) + "。")
    return "".join(lines)

